(function() {
    window._internalModHelpers = {}

    var fs = require('fs');
    var path = require('path');

    var modsPath = path.join(nw.App.dataPath, "mods");

    if (! fs.existsSync(modsPath)) {
        fs.mkdirSync(modsPath);
    }

    window._internalModHelpers.path = modsPath;

    window._internalModHelpers.getAllMods = function(then) {
        //Get all mods from %localappdata%
        fs.readdir(modsPath, { withFileTypes: true }, (err, files) => {
            if (err) throw err;
          
            var mods = [];

            for (const dirent of files) {
                if (dirent.isDirectory())
                    mods.push(dirent.name);
            }

            then(mods);
        });
    }

    window._internalModHelpers.getAllModsSteam = function() {
        let mods = [];
        //Get all mods from Steam workshop
        var items = greenworks.GetSubscribedItems();
        for (let item of items) {
            let folder = greenworks.TryGetItemFolder(item);
            mods.push("steamMod:///" + folder);
        }

        return mods;
    }

    window._internalModHelpers.getModFiles = function(modFolder, then) {
        fs.readdir(modFolder, { withFileTypes: true }, (err, files) => {
            if (err) { console.log("error loading mod"); throw err;}

            files.sort((a, b) => a.name.localeCompare(b.name, "en"));

            var modFiles = [];
            var waitingOn = 0, ready = false;

            for (const dirent of files) {
                if (dirent.isFile())
                    modFiles.push(path.join(modFolder,dirent.name));
                else if (dirent.isDirectory() && dirent.name !== "dontAutoLoad" && dirent.name !== ".git") {
                    waitingOn++;

                    window._internalModHelpers.getModFiles(path.join(modFolder, dirent.name), (files2) => {
                        waitingOn--;
                        for (const file of files2)
                            modFiles.push(file);

                        if (waitingOn == 0 && ready) {
                            then(modFiles);
                        }
                    });
                }
            }
            ready = true;
            if (waitingOn == 0) {
                then(modFiles);
            }
        });
    }

    window._internalModHelpers.readModFile = function(file, itemEncoding, onSuccess) {
        fs.readFile(file, {encoding: itemEncoding}, (err, dat) => {
            if (err) {
                if (onSuccess != null)
                    onSuccess(undefined);
                return;
            }
            if (onSuccess != null) {
                if (file.indexOf(".json") >= 0)
                    onSuccess(JSON.parse(dat));
                else
                    onSuccess(dat);
            }
        });
    };
    
    ModTools.version = 1.00;

    ModTools.makeBuilding = function(className, fields, spriteName, saveFunc, loadFunc, superClass) {
        var haxeClassName = "buildings." + className;
        var internalClassName = "buildings_" + className;
        
        //Choose super class based on buildinginfo.json info.
        if (superClass == undefined) {
            superClass = Building;

            const thisBuildingInfo = Resources.buildingInfo.h[haxeClassName];
            if (thisBuildingInfo == undefined) {
                throw "Building " + className + " is not defined in a buildinginfo.json.";
            }

            if (thisBuildingInfo.residents != undefined) {
                if (thisBuildingInfo.jobs != undefined)
                    superClass = buildings_WorkWithHome;
                else
                    superClass = buildings_House;
            } else if (thisBuildingInfo.jobs != undefined) {
                superClass = buildings_Work;
            }
        }

        var fieldsObject = {};
        if (typeof fields === "function")
            fieldsObject = fields(superClass);
        else
            fieldsObject = fields;

            fieldsObject.__init_extras__ = function() {}

        //Then build the class
        var constructorOfBuilding = fieldsObject["__constructor__"];
        if (constructorOfBuilding === undefined)
            constructorOfBuilding = function(game,stage,bgStage,city,world,position,worldPosition,id) {
                superClass.call(this,game,stage,bgStage,city,world,position,worldPosition,id);
                this.isEntertainment = this._getIsEntertainment();

                this.__init_extras__(stage, bgStage, city.cityBgStageAbove);
            };

        var newBuildingClass = window[internalClassName] = $hxClasses[haxeClassName] = constructorOfBuilding;
        newBuildingClass.__super__ = superClass;
        newBuildingClass.__name__ = haxeClassName;
        newBuildingClass.__interfaces__ = [];

        fieldsObject.__class__ = newBuildingClass;

        fieldsObject.save = function(queue) {
            var cur = queue.size;
            queue.addInt(0);

            superClass.prototype.save.call(this, queue);

            if (saveFunc != null)
                saveFunc.call(this, queue);

            queue.bytes.setInt32(cur, queue.size); 
        }

        fieldsObject.load = function(queue) {
            var queuePos = queue.readInt();

            superClass.prototype.load.call(this, queue);

            if (loadFunc != null)
                loadFunc.call(this, queue);

            // Just in case reset the queue read pos;
            // this should make it less likely that a mistake snowballs
            // into other save data.
            queue.readStart = queuePos;
        }
        
        fieldsObject._getIsEntertainment = () => false;

        newBuildingClass.prototype = $extend(superClass.prototype, fieldsObject);

        newBuildingClass.spriteName = spriteName;

        return newBuildingClass;
    }

    ModTools.buildingEnableMerging = function(building, mergeHorizontal=true, mergeVertical=false, canViewWalkthroughCitizensIfMergingBuildingBelow=false) {
        if (mergeHorizontal && mergeVertical)
            building.prototype.get_drawerType = () => buildings_buildingDrawers_AllDirMergingBuildingDrawer;
        else if (mergeHorizontal)
            building.prototype.get_drawerType = () => buildings_buildingDrawers_AutoMergingBuildingDrawer;
        else if (mergeVertical)
            building.prototype.get_drawerType = () => buildings_buildingDrawers_AutoMergingBuildingDrawerUD;

        if (mergeVertical && !canViewWalkthroughCitizensIfMergingBuildingBelow) {
            building.prototype.get_walkThroughCanViewSelfInThisBuilding = function() {
                if(this.bottomBuilding != null) {
                    return !this.bottomBuilding.is(building);
                } else {
                    return true;
                }
            }
        }
    }

    //A simple way to add an animated sprite to a building
    ModTools.buildingAddAnimatedSprite = function(building, spriteName, spriteFrameWidth, onUpdate, x=0, y=0, layer=upgradeDisplayLayer.Background) {
        if (building.prototype.animatedSpriteNumber == undefined)
            building.prototype.animatedSpriteNumber = 0;

        var animatedSpriteNum = building.prototype.animatedSpriteNumber;
        
        building.prototype.animatedSpriteNumber += 1;
        
        //Init
        (function(existingFunction) {
            building.prototype.__init_extras__ = function (stage, bgStage, midStage) {
                existingFunction.call(this, stage, bgStage, midStage);

                if (this.animatedSpriteTextures == null)
                    this.animatedSpriteTextures = [];
                if (this.animatedSpriteSprites == null)
                    this.animatedSpriteSprites = [];
        
                //Create the new sprite
                this.animatedSpriteTextures[animatedSpriteNum] = Resources.getTexturesByWidth(spriteName, spriteFrameWidth);
                this.animatedSpriteSprites[animatedSpriteNum] = new PIXI.Sprite();

                this.animatedSpriteSprites[animatedSpriteNum].position.set(this.position.x + x, this.position.y + y);

                switch (layer) {
                    case upgradeDisplayLayer.Background: bgStage.addChild(this.animatedSpriteSprites[animatedSpriteNum]); break;
                    case upgradeDisplayLayer.Middle: midStage.addChild(this.animatedSpriteSprites[animatedSpriteNum]); break;
                    case upgradeDisplayLayer.Foreground: stage.addChild(this.animatedSpriteSprites[animatedSpriteNum]); break;
                }

                this.animatedSpriteSprites[animatedSpriteNum].texture
                    = this.animatedSpriteTextures[animatedSpriteNum]
                        [Math.floor(onUpdate.call(this, 0, this.animatedSpriteTextures[animatedSpriteNum].length,
                            this.animatedSpriteSprites[animatedSpriteNum]))];
            };
        }(building.prototype.__init_extras__));

        //Position sprites
        if (building.prototype.positionSprites == undefined) {
            building.prototype.positionSprites = function() {
                this.__super__.prototype.positionSprites.call(this);
            };
        }

        (function(existingFunction) {
            building.prototype.positionSprites = function () {
                existingFunction.call(this);

                this.animatedSpriteSprites[animatedSpriteNum].position.set(this.position.x + x, this.position.y + y);
            };
        }(building.prototype.positionSprites));

        //Update
        if (building.prototype.update == undefined) {
            if (this.__super__.prototype.update != null)
                building.prototype.update = function(timeMod) {
                    this.__super__.prototype.update.call(this, timeMod);
                };
            else
                building.prototype.update = function() {};
        }

        (function(existingFunction) {
            building.prototype.update = function (timeMod) {
                existingFunction.call(this, timeMod);

                this.animatedSpriteSprites[animatedSpriteNum].texture
                    = this.animatedSpriteTextures[animatedSpriteNum]
                        [Math.floor(onUpdate.call(this, timeMod,
                            this.animatedSpriteTextures[animatedSpriteNum].length,
                            this.animatedSpriteSprites[animatedSpriteNum]))];
            };
        }(building.prototype.update));

        //Destroy
        if (building.prototype.destroy == undefined) {
            building.prototype.destroy = function() {
                this.__super__.prototype.destroy.call(this);
            };
        }

        (function(existingFunction) {
            building.prototype.destroy = function (timeMod) {
                existingFunction.call(this, timeMod);

                this.animatedSpriteSprites[animatedSpriteNum].destroy();
            };
        }(building.prototype.destroy));
    }
 
    ModTools.buildingAddEntertainmentProperties = function(building, getEntertainmentCapacity,
        beEntertained, entertainmentType, minimumNormalTimeToSpend, maximumNormalTimeToSpend,
        minimumEntertainmentGroupSatisfy, maximumEntertainmentGroupSatisfy, isOpenFunc) {
        building.__interfaces__.push(buildings_IEntertainmentBuilding);

        building.prototype._getIsEntertainment = () => true;
        building.prototype.get_entertainmentQuality = () => 100;
        building.prototype.beEntertained = beEntertained;
        building.prototype.get_entertainmentType = () => entertainmentType;
        building.prototype.get_isOpen = isOpenFunc;
        building.prototype.get_baseEntertainmentCapacity = getEntertainmentCapacity;
        building.prototype.get_minimumNormalTimeToSpend = () => minimumNormalTimeToSpend;
        building.prototype.get_maximumNormalTimeToSpend = () => maximumNormalTimeToSpend;
        building.prototype.get_minimumEntertainmentGroupSatisfy = () => minimumEntertainmentGroupSatisfy;
        building.prototype.get_maximumEntertainmentGroupSatisfy = () => maximumEntertainmentGroupSatisfy;
        building.prototype.finishEntertainment = (citizen, timeMod) => true;
        building.prototype.get_isOpenForExistingVisitors = function() {
            return this.get_isOpen();
        };
        Building.prototype.get_secondaryEntertainmentTypes = function() {
            return null;
        }
    }

    ModTools.makeBuildingUpgrade = function(className, fields, onCreate, spriteName, stageToUse) {
        if (spriteName == null)
            spriteName = "";

        var haxeClassName = "buildingUpgrades." + className;
        var internalClassName = "buildingUpgrades_" + className;
            
        var newUpgradeClass = window[internalClassName] = function(stdStage,midStage,bgStage,building) {
            var stageToUseActual = stdStage;
            if (stageToUse == 2)
                stageToUseActual = midStage;
            if (stageToUse == 1)
                stageToUseActual = bgStage;
            if (spriteName == "")
                stageToUseActual = null;
            BuildingUpgrade.call(this, stageToUseActual, building);
            building.buildingEnabled = true;

            if (onCreate != null)
                onCreate.call(this, building);
        };
        $hxClasses[haxeClassName] = newUpgradeClass;
        newUpgradeClass.__name__ = haxeClassName;
        newUpgradeClass.__super__ = BuildingUpgrade;

        var fieldsObject = {};
        if (typeof fields === "function")
            fieldsObject = fields(BuildingUpgrade);
        else
            fieldsObject = fields;
        fieldsObject.__class__ = newUpgradeClass;
        fieldsObject.get_textureName = () => { return spriteName; };

        newUpgradeClass.prototype = $extend(BuildingUpgrade.prototype, fieldsObject);

        return newUpgradeClass;
    }

    ModTools.makeCityUpgrade = function(className, addToCity, fields) {
        var haxeClassName = "cityUpgrades." + className;
        var internalClassName = "cityUpgrades_" + className;
            
        var newUpgradeClass = window[internalClassName] = function() {
            cityUpgrades_CityUpgrade.call(this);
        };
        $hxClasses[haxeClassName] = newUpgradeClass;
        newUpgradeClass.__name__ = haxeClassName;
        newUpgradeClass.__super__ = cityUpgrades_CityUpgrade;

        var fieldsObject = {};
        if (fields != null) {
            if (typeof fields === "function")
                fieldsObject = fields(cityUpgrades_CityUpgrade);
            else
                fieldsObject = fields;
        }
        if (fieldsObject.addToCity == null)
            fieldsObject.addToCity = addToCity;
        fieldsObject.__class__ = newUpgradeClass;

        newUpgradeClass.prototype = $extend(cityUpgrades_CityUpgrade.prototype, fieldsObject);

        return newUpgradeClass;
    }

    ModTools.addUpgradeToBuilding = function(buildingClass, upgradeClass) {
        if (typeof buildingClass === "string") {
            buildingClass = $hxClasses["buildings." + buildingClass];
        }
        if (typeof upgradeClass === "string") {
            upgradeClass = $hxClasses["buildingUpgrades." + upgradeClass];
            if (upgradeClass == null) {
                upgradeClass = $hxClasses["cityUpgrades." + upgradeClass];
            }
        }

        if (upgradeClass.__name__.startsWith("cityUpgrades.")) {
            (function(existingFunction) {
                buildingClass.prototype.get_possibleCityUpgrades = function () {
                    var upgrades = existingFunction.call(this);
            
                    return upgrades.concat([upgradeClass]);
                };
            }(buildingClass.prototype.get_possibleCityUpgrades));
        } else {
            (function(existingFunction) {
                buildingClass.prototype.get_possibleUpgrades = function () {
                    var upgrades = existingFunction.call(this);
            
                    return upgrades.concat([upgradeClass]);
                };
            }(buildingClass.prototype.get_possibleUpgrades));
        }
    }
})();